module multi_pipe_4bit(
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

parameter SIZE = 4;

reg [SIZE-1:0] reg1, reg2, reg3, reg4;
reg [SIZE:0] reg5, reg6, reg7;
reg [(SIZE*(SIZE-1))/2:0] partial_products;

always @(*) begin
    if (!rst_n) begin
        partial_products = 0;
    end else begin
        partial_products = {4'b0, mul_a};
        for (int i = 0; i < SIZE; i++) begin
            if (mul_b[i]) begin
                partial_products = partial_products + (mul_a << i);
            end
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg1 <= 0;
        reg2 <= 0;
        reg3 <= 0;
        reg4 <= 0;
        reg5 <= 0;
        reg6 <= 0;
        reg7 <= 0;
    end else begin
        reg1 <= partial_products[(SIZE*(SIZE-1))/2 - 1:(SIZE-1)/2];
        reg2 <= partial_products[(SIZE-1)/2 - 1:(SIZE-1)%2];
        reg3 <= partial_products[(SIZE-1)%2 - 1:0];
        reg4 <= partial_products[SIZE - 1:0];
        reg5 <= reg1 + reg2;
        reg6 <= reg3 + reg4;
        reg7 <= reg5 + reg6;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 0;
    end else begin
        mul_out <= reg5 + reg7;
    end
end

endmodule
